function renderStatusBars(results) {
  pollStatusBars.replaceChildren();
  if (!results) return;
  const { poll, total, counts } = results;
  pollStatusCount.textContent = total + ' Antwort' + (total !== 1 ? 'en' : '');

  if (poll.kind === 'multiple_choice') {
    counts.forEach(c => {
